-- GIN index on JSONB replaces a DynamoDB GSI on Map attributes
CREATE TABLE posts (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  metadata    JSONB,
  embedding   vector(1536)
);

CREATE INDEX idx_meta_gin  ON posts USING GIN  (metadata);
CREATE INDEX idx_embed_hnsw ON posts USING hnsw (embedding vector_cosine_ops);

-- Containment query — no WCUs, no eventual lag
SELECT id FROM posts
WHERE metadata @> '{"author": "alice", "tag": "dynamodb"}';

-- ANN semantic search — no OpenSearch sidecar needed
SELECT id FROM posts
ORDER BY embedding <=> '[0.12, 0.07, ...]'::vector
LIMIT 5;

import { DynamoDBClient, QueryCommand } from "@aws-sdk/client-dynamodb";
import { marshall, unmarshall } from "@aws-sdk/util-dynamodb";

const client = new DynamoDBClient({ region: "us-east-1" });

// Single-table: fetch all orders for a user via GSI
const result = await client.send(new QueryCommand({
  TableName: "AppTable",
  IndexName: "GSI1",
  KeyConditionExpression: "GSI1PK = :pk AND begins_with(GSI1SK, :prefix)",
  ExpressionAttributeValues: marshall({
    ":pk": "USER#u_42",
    ":prefix": "ORDER#",
  }),
}));

const orders = result.Items?.map(unmarshall) ?? [];

from elasticsearch import Elasticsearch, helpers

es = Elasticsearch("http://localhost:9200")

# Lambda: DynamoDB Streams → ES bulk index
def handler(event, context):
    docs = [{
        "_index": "products",
        "_id": r["dynamodb"]["NewImage"]["pk"]["S"],
        "title": r["dynamodb"]["NewImage"]["title"]["S"],
        "description": r["dynamodb"]["NewImage"]["description"]["S"],
    } for r in event["Records"] if r["eventName"] == "INSERT"]
    helpers.bulk(es, docs)

    # Query DSL replaces FilterExpression — no RCUs consumed
    return es.search(index="products", body={
        "query": {"bool": {
            "must": {"multi_match": {"query": "wireless headphones", "fields": ["title^2", "description"]}},
            "filter": {"range": {"price": {"lte": 200}}}
        }},
        "aggs": {"tags": {"terms": {"field": "tags.keyword"}}}
    })

import { DynamoDBClient, QueryCommand } from "@aws-sdk/client-dynamodb";
import { marshall } from "@aws-sdk/util-dynamodb";

const client = new DynamoDBClient({ region: "us-east-1" });

// Sparse GSI: only orders with `openStatus` attribute are indexed.
// On fulfillment, delete the attribute — item auto-drops from the index.
const { Items } = await client.send(new QueryCommand({
  TableName: "Orders",
  IndexName: "open-orders-gsi",
  KeyConditionExpression: "openStatus = :v",
  ExpressionAttributeValues: marshall({ ":v": "true" }),
}));

