import { DynamoDBClient, TransactWriteItemsCommand } from "@aws-sdk/client-dynamodb";

const client = new DynamoDBClient({});

// Optimistic lock: aborts if version drifted or credits insufficient
await client.send(new TransactWriteItemsCommand({
  TransactItems: [{
    Update: {
      TableName: "Accounts",
      Key: { userId: { S: fromId } },
      UpdateExpression: "SET credits = credits - :amt, #v = #v + :one",
      ConditionExpression: "#v = :ver AND credits >= :amt",
      ExpressionAttributeNames: { "#v": "version" },
      ExpressionAttributeValues: {
        ":amt": { N: `${amount}` }, ":one": { N: "1" }, ":ver": { N: `${expectedVersion}` },
      },
    },
  }],
  ClientRequestToken: `xfer-${fromId}-${Date.now()}`,
}));

import boto3, random
from boto3.dynamodb.conditions import Key

table = boto3.resource("dynamodb").Table("Votes")
NUM_SHARDS = 5

def cast_vote(topic_id: str, user_id: str) -> None:
    shard = random.randint(0, NUM_SHARDS - 1)
    table.put_item(Item={
        "pk": f"{topic_id}#{shard}",
        "sk": user_id,
    })

def count_votes(topic_id: str) -> int:
    total = 0
    for shard in range(NUM_SHARDS):
        resp = table.query(
            KeyConditionExpression=Key("pk").eq(f"{topic_id}#{shard}"),
            Select="COUNT"
        )
        total += resp["Count"]
    return total
